module RefModule(  
    input clk,  
    input rst,  
    input start,  
    input ack,  
    input done,  
    output reg [1:0] current_state  
);  
    // State encoding  
    localparam IDLE = 2'b00,  
               REQUEST = 2'b01,  
               RESPONSE = 2'b10;  

    // State register  
    reg [1:0] ctrl_bus_wire;  

    // Sequential logic for state transition  
    always @(posedge clk or posedge rst) begin  
        if (rst)  
            current_state <= IDLE;  
        else  
            current_state <= ctrl_bus_wire;  
    end  

    // Combinational logic for next state  
    always @(*) begin  
        case (current_state)  
            IDLE: begin  
                if (start)  
                    ctrl_bus_wire = REQUEST;  
                else  
                    ctrl_bus_wire = IDLE;  
            end  
            REQUEST: begin  
                if (ack)  
                    ctrl_bus_wire = RESPONSE;  
                else  
                    ctrl_bus_wire = REQUEST;  
            end  
            RESPONSE: begin  
                if (done)  
                    ctrl_bus_wire = IDLE;  
                else  
                    ctrl_bus_wire = RESPONSE;  
            end  
            default: ctrl_bus_wire = IDLE;  
        endcase  
    end  
endmodule
